#include <stdio.h>

int main() {
    int n, a, b, c;
    scanf("%d", &n);
    scanf("%d", &a);
    scanf("%d", &b);
    scanf("%d", &c);
    int count = 0;
    while (n >= a || n >= b) {
        if (b - c < a && n / b > 0) {
            int temp = (n - c) / (b - c);
            count += temp;
            n -= temp * (b - c);
        } else {
            int temp = n / a;
            count += temp;
            n -= temp * a;
        }
    }
    printf("%d\n", count);
    return 0;
}
